ytenant_id = #{ytenantId}
and (isrepeat in (0,3) or isrepeat is null)
and currency = #{currency}
and accentity = #{accentity}
and bankaccount = #{bankaccount}

    and remark != #{remark}

and tran_date BETWEEN #{startDate} and #{endDate};

